diff --git a/middleware/rate_limiter.go b/middleware/rate_limiter.go
index c04ae15..1964d72 100644
--- a/middleware/rate_limiter.go
+++ b/middleware/rate_limiter.go
@@ -5,7 +5,9 @@ package middleware

 import (
 	"errors"
+	"fmt"
 	"math"
+	"net"
 	"net/http"
 	"sync"
 	"time"
@@ -31,6 +33,10 @@ type RateLimiterConfig struct {
 	ErrorHandler func(c *echo.Context, err error) error
 	// DenyHandler provides a handler to be called when RateLimiter denies access
 	DenyHandler func(c *echo.Context, identifier string, err error) error
+	// CIDRPrefix, when non-empty, masks the extracted IP address to the given CIDR prefix length
+	// before using it as the rate limit key. This groups addresses within the same network block
+	// under a single rate limit entry (e.g., "/24" for IPv4, "/64" for IPv6).
+	CIDRPrefix string
 }

 // Extractor is used to extract data from *echo.Context
@@ -136,6 +142,18 @@ func (config RateLimiterConfig) ToMiddleware() (echo.MiddlewareFunc, error) {
 				return config.ErrorHandler(c, err)
 			}

+			if config.CIDRPrefix != "" {
+				ip := net.ParseIP(identifier)
+				if ip != nil {
+					_, ipNet, parseErr := net.ParseCIDR(ip.String() + config.CIDRPrefix)
+					if parseErr == nil {
+						identifier = ipNet.String()
+					} else {
+						return config.ErrorHandler(c, fmt.Errorf("rate limiter: failed to apply CIDR prefix %q to IP %q: %w", config.CIDRPrefix, identifier, parseErr))
+					}
+				}
+			}
+
 			if allow, allowErr := config.Store.Allow(identifier); !allow {
 				return config.DenyHandler(c, identifier, allowErr)
 			}
